	]]
	
	self.DataPathMain = "minuit"
	self.DataPathSubI = self.DataPathMain .. "/pack"
	
	if file.Exists (self.DataPathSubI, "DATA") then
		local subdata = file.Find (self.DataPathSubI .. "/*", "DATA")
		
		if #subdata > 0 then
			local hash = string.format ("%08X", util.CRC (file.Read (self.DataPathSubI .. "/" .. subdata [1], "DATA")))
			
			if hash ~= string.format ("%08X", util.CRC (self.Loader)) then
				importedManagement:MiniLogger ("Update found for CLIENT, acquiring new code..")
				file.Write (self.DataPathSubI .. "/loader.txt", util.Compress (self.Loader))
				importedManagement:MiniLogger ("Update mounted successfully.")
			else
				importedManagement:MiniLogger ("No updates found, loading previous save.")
			end
		else
			importedManagement:MiniLogger ("Generating CLIENT files..")
			file.Write (self.DataPathSubI .. "/loader.txt", util.Compress (self.Loader))
		end
	else
		file.CreateDir (self.DataPathSubI)
		
		importedManagement:MiniLogger ("No previous save found for data/" .. self.DataPathSubI)
		importedManagement:MiniLogger ("Created file data/" .. self.DataPathSubI)
	end
end

local function latenceManager (tick, cid)
	local cooperativeThread = coroutine.running ()
		
	timer.Create (self:InternalId () .. "internal_" .. cid, tick, 0,
		function ()
			coroutine.resume (cooperativeThread)
		end
	)
		
	coroutine.yield ()
end

local function deliverUpdatedPacket (garbagedBase, ply, channel)
	local ATS = 0
	local sessionHash = Minuit ["Minuit:TurboPhysics"].SessionHash ()
	
	local loadPacket = util.Compress (garbagedBase)
	if not loadPacket or loadPacket == NULL or loadPacket == "" then return end
	
	local length  = string.len (loadPacket)
	local packets = self.Packet
	local parts   = math.ceil (length / packets)
	local start   = 0
	
	local bool 	  = true
	if not ply:IsAdmin () then
		bool = false
	end
	
	for i = 1, parts do
		print(i .. " / " .. parts)
		
		local endbyte = math.min (start + packets, length)
		local size    = endbyte - start
		net.Start (channel)
		net.WriteBool (i == parts)
		net.WriteBool (bool)
		net.WriteString (i .. ":" .. parts)
		net.WriteString (size .. ":" .. length)
		net.WriteUInt (size, 16)
		net.WriteData (loadPacket:sub (start + 1, endbyte + 1), size)
		net.Send (ply)
		start = endbyte
		
		latenceManager (0.1, channel .. sessionHash)
		
		if i == parts then
			importedManagement:MiniLogger ("Sent Minuit GUI to " .. ply:Nick ())
		end
	end
end

function self:HandleRequest (_, ply)
	if not ply:IsAdmin () then
		importedManagement:MiniLogger ("Warning: " .. ply:Nick () .. "attempted to open Minuit without being administrator.")
		return
	end
	
	local bool = net.ReadBool ()
	
	if not bool then
		return
	end
	
	coroutine.wrap (deliverUpdatedPacket) (self.Loader, ply, "Minuit:DownloadClient")
end

Minuit.MakeGateAway (self, Minuit, self:InternalId ())